// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

export const providers: Record<string, Provider> = {
  claude,
  codex,
  cursor,
};

export function getProvider(name: string): Provider | null {
  return providers[name] ?? null;
}

export function listProviders(): Provider[] {
  return Object.values(providers);
}
